 58→// Animated number hook for smooth credit transitions
 59→const useAnimatedNumber = (value: number, duration = 600) => {
 60→  const [display, setDisplay] = useState(value);
 61→  const prevValue = useRef(value);
 62→  useEffect(() => {
 63→    if (prevValue.current === value) return;
 64→    const start = prevValue.current;
 65→    const diff = value - start;
 66→    const startTime = performance.now();
 67→    const animate = (now: number) => {
 68→      const progress = Math.min((now - startTime) / duration, 1);
 69→      const eased = 1 - Math.pow(1 - progress, 3);
 70→      setDisplay(Math.round(start + diff * eased));
 71→      if (progress < 1) requestAnimationFrame(animate);
 72→    };
 73→    requestAnimationFrame(animate);
 74→    prevValue.current = value;
 75→  }, [value, duration]);
 76→  return display;
 77→};
