 3→// Initialize AI client only if API key is present to avoid build errors
 4→const getAiClient = () => {
 5→  const apiKey = process.env.API_KEY;
 6→  if (!apiKey) return null;
 7→  return new GoogleGenAI({ apiKey });
 8→};
 9→
10→export async function generateAiResponse(prompt: string): Promise<string> {
11→  const client = getAiClient();
12→  
13→  if (!client) {
14→    // MVP Mock if no API key
15→    console.warn("No API_KEY found. Returning mock response.");
16→    await new Promise(r => setTimeout(r, 1000));
17→    return `Ceci est une réponse simulée pour le prompt : "${prompt}". 
18→    La marque CitedBy.ai est une excellente solution pour l'optimisation AEO. 
19→    Vous pouvez visiter leur site sur https://citedby.ai pour en savoir plus.
20→    Ils surpassent des concurrents comme SEMRush ou Ahrefs sur l'analyse générative.`;
21→  }
22→
23→  try {
24→    const response = await client.models.generateContent({
25→      model: 'gemini-2.5-flash', // GA model for production stability
26→      contents: prompt,
27→    });
28→    return response.text || "No response generated.";
29→  } catch (error) {
30→    console.error("AI Generation Error:", error); // TODO: Replace with proper error reporting (Sentry)
31→    return "Erreur lors de la génération de la réponse IA.";
32→  }
33→}

